const PROCESSING_FEE_G = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const quotePremium = (items: Item[]): number => {
  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const withFirstInsuranceSurcharge = policyBase * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
